Create the `SchedulesView` component — a read-only summary of Pulse schedules with active/upcoming grouping, empty states, and a bridge button to the full Pulse panel.

## File Location

`apps/client/src/layers/features/session-list/ui/SchedulesView.tsx`

## Props Interface

```typescript
import type { ChipState } from '@/layers/entities/agent';

interface SchedulesViewProps {
  /** Per-agent Pulse chip state from useAgentToolStatus */
  toolStatus: ChipState;
}
```

## Full Component Implementation

```tsx
import { useSchedules, useActiveRunCount } from '@/layers/entities/pulse';
import { useAppStore } from '@/layers/shared/model';
import { useElapsedTime } from '@/layers/shared/model';
import type { ChipState } from '@/layers/entities/agent';
import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuItem,
  SidebarMenuButton,
  ScrollArea,
} from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import { formatRelativeTime } from '@/layers/shared/lib';

interface SchedulesViewProps {
  toolStatus: ChipState;
}

/** Read-only schedule summary for the sidebar Schedules tab. */
export function SchedulesView({ toolStatus }: SchedulesViewProps) {
  const setPulseOpen = useAppStore((s) => s.setPulseOpen);
  const enabled = toolStatus !== 'disabled-by-server';
  const { data: schedules = [] } = useSchedules(enabled);
  const { data: activeRunCount = 0 } = useActiveRunCount(enabled);

  // Disabled-by-agent state
  if (toolStatus === 'disabled-by-agent') {
    return (
      <div className="flex flex-col items-center justify-center gap-3 px-4 py-8">
        <p className="text-muted-foreground/60 text-sm">Pulse disabled for this agent</p>
        <button
          onClick={() => setPulseOpen(true)}
          className="text-muted-foreground hover:text-foreground text-xs transition-colors"
        >
          Open Pulse \u2192
        </button>
      </div>
    );
  }

  // Separate active (running) and upcoming schedules
  const activeSchedules = schedules.filter((s) => s.status === 'running');
  const upcomingSchedules = schedules.filter((s) => s.status !== 'running');

  // Empty state
  if (schedules.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center gap-3 px-4 py-8">
        <p className="text-muted-foreground/60 text-sm">No schedules configured</p>
        <button
          onClick={() => setPulseOpen(true)}
          className="text-muted-foreground hover:text-foreground text-xs transition-colors"
        >
          Open Pulse \u2192
        </button>
      </div>
    );
  }

  return (
    <ScrollArea type="scroll" className="h-full">
      <div className="pr-1">
        {activeSchedules.length > 0 && (
          <SidebarGroup>
            <SidebarGroupLabel className="text-2xs text-muted-foreground/70 font-medium tracking-wider uppercase">
              Active
            </SidebarGroupLabel>
            <SidebarMenu>
              {activeSchedules.map((schedule) => (
                <SidebarMenuItem key={schedule.id}>
                  <SidebarMenuButton
                    onClick={() => setPulseOpen(true)}
                    className="text-sm"
                  >
                    <span className="size-2 shrink-0 animate-pulse rounded-full bg-green-500" />
                    <span className="truncate">{schedule.name}</span>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroup>
        )}

        {upcomingSchedules.length > 0 && (
          <SidebarGroup>
            <SidebarGroupLabel className="text-2xs text-muted-foreground/70 font-medium tracking-wider uppercase">
              Upcoming
            </SidebarGroupLabel>
            <SidebarMenu>
              {upcomingSchedules.map((schedule) => (
                <SidebarMenuItem key={schedule.id}>
                  <SidebarMenuButton
                    onClick={() => setPulseOpen(true)}
                    className="text-sm"
                  >
                    <span
                      className={cn(
                        'size-2 shrink-0 rounded-full',
                        schedule.enabled ? 'bg-muted-foreground/40' : 'bg-muted-foreground/20'
                      )}
                    />
                    <span className="truncate">{schedule.name}</span>
                    {schedule.nextRunAt && (
                      <span className="text-muted-foreground/50 ml-auto text-xs">
                        {formatRelativeTime(schedule.nextRunAt)}
                      </span>
                    )}
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroup>
        )}

        {/* Bridge button to full Pulse panel */}
        <div className="px-3 py-2">
          <button
