Create a derived hook that computes the aggregate connection status for the Connections tab badge dot.

## File Location

`apps/client/src/layers/features/session-list/model/use-connections-status.ts`

This creates the `model/` segment within the `session-list` feature module. Create the directory if it does not exist.

## Full Implementation

```typescript
import { useMemo } from 'react';
import { useAgentToolStatus } from '@/layers/entities/agent';
import { useRelayAdapters } from '@/layers/entities/relay';
import { useRegisteredAgents } from '@/layers/entities/mesh';

/**
 * Derive aggregate connection status for the Connections tab badge.
 *
 * @param projectPath - Working directory path for per-agent tool status resolution.
 * @returns Aggregate status: 'ok' (all healthy), 'partial' (some issues), 'error' (failures), 'none' (no connections).
 */
export function useConnectionsStatus(
  projectPath: string | null
): 'ok' | 'partial' | 'error' | 'none' {
  const toolStatus = useAgentToolStatus(projectPath);
  const relayEnabled = toolStatus.relay !== 'disabled-by-server';
  const meshEnabled = toolStatus.mesh !== 'disabled-by-server';
  const { data: adapters } = useRelayAdapters(relayEnabled);
  const { data: agentsData } = useRegisteredAgents(undefined, meshEnabled);
  const agents = agentsData?.agents;

  return useMemo(() => {
    const items = [...(adapters ?? []), ...(agents ?? [])];
    if (items.length === 0) return 'none';
    const hasError = adapters?.some((a) => a.status === 'error');
    if (hasError) return 'error';
    const allConnected = adapters?.every((a) => a.status === 'connected') ?? true;
    const allOnline = agents?.every((a) => a.status === 'online') ?? true;
    if (allConnected && allOnline) return 'ok';
    return 'partial';
  }, [adapters, agents]);
}
```

